  if (!content.trim()) {
    console.error("[SECURITY] package-lock.json is empty or invalid");
    process.exit(1);
  }
}

function verifyCriticalDependencies(): void {
  if (!depConfig.enabled) return;

  for (const dep of depConfig.criticalFiles) {
    if (!dep.expectedHash) {
      console.error(`[SECURITY] Missing expected hash for ${dep.name}@${dep.version}`);
      process.exit(1);
    }

