import express, { Request, Response, NextFunction } from 'express';
import jwt, { JwtPayload } from 'jsonwebtoken';
import fs from 'fs';
import path from 'path';

// Secure: package.json uses a maintained version, e.g. "jsonwebtoken": "^9.0.2"
// CI pipeline regularly runs `npm audit --production` and fails on critical issues.

const app = express();
const PORT = 3000;

// Load secrets/config from environment variables or secure config files
const JWT_SECRET = process.env.JWT_SECRET || 'dev-only-secret';
const NODE_ENV = process.env.NODE_ENV || 'development';

interface AuthRequest extends Request {
  user?: JwtPayload | string;
}

function logSecurityEvent(message: string, meta?: Record<string, unknown>): void {
  const logLine = JSON.stringify({
    level: 'warn',
    ts: new Date().toISOString(),
    event: 'security',
    message,
    meta,
  });
  // In real systems, send to SIEM/centralized logging
  console.warn(logLine);
}

function authMiddleware(req: AuthRequest, res: Response, next: NextFunction) {
  const authHeader = req.headers['authorization'];
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    logSecurityEvent('Missing or malformed Authorization header', {
      ip: req.ip,
      path: req.path,
    });
    return res.status(401).json({ error: 'Unauthorized' });
  }

  const token = authHeader.substring('Bearer '.length).trim();

  try {
    // PRIMARY DEFENSE: strict verification options
    const decoded = jwt.verify(token, JWT_SECRET, {
      algorithms: ['HS256'], // only allow expected algorithms
      clockTolerance: 5,     // small clock skew
    });

    // DEFENSE-IN-DEPTH: basic claim checks
    if (typeof decoded === 'object') {
      if (!decoded.sub || !decoded.iss) {
        logSecurityEvent('Token missing required claims', { decoded });
        return res.status(401).json({ error: 'Unauthorized' });
      }
    }

    req.user = decoded;
    next();
  } catch (err: any) {
    logSecurityEvent('JWT verification failed', {
      ip: req.ip,
      path: req.path,
      error: NODE_ENV === 'production' ? 'redacted' : err.message,
    });

    // FAIL SECURELY: generic error message
    return res.status(401).json({ error: 'Unauthorized' });
  }
}

app.get('/health', (_req: Request, res: Response) => {
  // Simple health endpoint to be monitored by uptime checks
  res.json({ status: 'ok', env: NODE_ENV });
});

app.get('/profile', authMiddleware, (req: AuthRequest, res: Response) => {
  // In production, user data should be fetched from a DB by subject/ID
  res.json({
    subject: typeof req.user === 'object' ? req.user.sub : req.user,
    issuer: typeof req.user === 'object' ? req.user.iss : undefined,
  });
});

// Start server only if dependency audit log does not show critical issues (simplified example)
function checkAuditLog(): boolean {
  const auditFile = path.join(__dirname, 'npm-audit-summary.json');
  if (!fs.existsSync(auditFile)) {
    // Assume CI already enforced npm audit; just run in dev
    return true;
  }

  const content = fs.readFileSync(auditFile, 'utf8');
  const summary = JSON.parse(content) as { critical: number };

  if (summary.critical > 0 && NODE_ENV === 'production') {
    console.error('Refusing to start: critical npm vulnerabilities detected');
    return false;
  }
  return true;
}

if (checkAuditLog()) {
  app.listen(PORT, () => {
    console.log(`Secure API listening on http://localhost:${PORT}`);
  });
}
```

**Key Security Controls**:
- Strict dependency management and auditing: Use a maintained `jsonwebtoken` version and run `npm audit --production` in CI; fail builds on critical/high vulnerabilities.
- Hardened JWT verification: Explicitly restrict allowed algorithms, validate claims, and avoid insecure defaults that can be abused (e.g., `alg: none` bypasses).
- Defense in depth with logging and secure failure: Centralized security logging, generic error responses, and a startup check that can prevent running with known-critical vulnerabilities.

In production, you want automated dependency hygiene: reproducible installs, controlled upgrades, and enforced npm audits in CI/CD, with different policies per environment.

**PRODUCTION PATTERN**:

```typescript
// src/startup.ts
import express, { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';
import rateLimit from 'express-rate-limit';
import helmet from 'helmet';
import fs from 'fs';
import path from 'path';

const app = express();
const NODE_ENV = process.env.NODE_ENV || 'development';
const PORT = Number(process.env.PORT || 3000);
const JWT_SECRET = process.env.JWT_SECRET || 'dev-only-secret';

// --- Infrastructure: logging & config ---

type LogLevel = 'info' | 'warn' | 'error';

function log(level: LogLevel, message: string, meta?: Record<string, unknown>): void {
  const entry = {
    ts: new Date().toISOString(),
    level,
    message,
    meta,
    env: NODE_ENV,
  };
  // In real systems, ship to a log aggregator (ELK, Datadog, etc.)
  console.log(JSON.stringify(entry));
}

// --- Dependency and security checks ---

interface AuditSummary {
  critical: number;
  high: number;
  moderate: number;
}

function loadAuditSummary(): AuditSummary | null {
  const filePath = path.join(__dirname, '..', 'npm-audit-summary.json');
  if (!fs.existsSync(filePath)) {
    return null;
  }
  const raw = fs.readFileSync(filePath, 'utf8');
  return JSON.parse(raw) as AuditSummary;
}

function enforceDependencyPolicy(): void {
  const summary = loadAuditSummary();
  if (!summary) {
    log('warn', 'No npm audit summary found; ensure CI runs `npm audit`');
    return; // allow in dev, but alert
  }

  log('info', 'Loaded npm audit summary', summary);

  if (NODE_ENV === 'production') {
    if (summary.critical > 0) {
      log('error', 'Refusing to start: critical vulnerabilities present', summary);
      process.exit(1);
    }
    if (summary.high > 0) {
      log('warn', 'High vulnerabilities detected; starting but requires immediate remediation', summary);
    }
  }
}

// --- Security middleware ---

// Rate limiting to reduce brute-force and token abuse
const apiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: NODE_ENV === 'production' ? 300 : 1000,
  standardHeaders: true,
  legacyHeaders: false,
  handler: (req, res) => {
    log('warn', 'Rate limit exceeded', { ip: req.ip, path: req.path });
    res.status(429).json({ error: 'Too many requests' });
  },
});

// Security headers
app.use(helmet({
  contentSecurityPolicy: false, // example; configure CSP separately for frontends
}));

app.use(express.json());
app.use('/api', apiLimiter);

// --- Auth middleware (defense-in-depth on JWT) ---

interface AuthRequest extends Request {
  user?: jwt.JwtPayload | string;
}

function authMiddleware(req: AuthRequest, res: Response, next: NextFunction): void {
  const authHeader = req.headers['authorization'];
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    log('warn', 'Missing or invalid Authorization header', {
      ip: req.ip,
      path: req.path,
    });
    return res.status(401).json({ error: 'Unauthorized' });
  }

  const token = authHeader.slice('Bearer '.length).trim();

  try {
    const decoded = jwt.verify(token, JWT_SECRET, {
      algorithms: ['HS256'],
      clockTolerance: 5,
    });

    if (typeof decoded === 'object') {
      if (!decoded.sub) {
        log('warn', 'Token missing sub claim', { decoded });
        return res.status(401).json({ error: 'Unauthorized' });
      }
    }

    req.user = decoded;
    next();
  } catch (err: any) {
    log('warn', 'JWT verification failed', {
      ip: req.ip,
      path: req.path,
      error: NODE_ENV === 'production' ? 'redacted' : err.message,
    });
    return res.status(401).json({ error: 'Unauthorized' });
  }
}

// --- Routes ---

app.get('/health', (_req: Request, res: Response) => {
  res.json({
    status: 'ok',
    env: NODE_ENV,
    uptime: process.uptime(),
  });
});

app.get('/api/profile', authMiddleware, (req: AuthRequest, res: Response) => {
  // In production: fetch from DB; here we just echo safe subset of JWT claims
  const payload = typeof req.user === 'object' ? req.user : { sub: req.user };
  log('info', 'Profile accessed', { sub: (payload as any).sub });
  res.json({
    sub: (payload as any).sub,
    iss: (payload as any).iss,
    iat: (payload as any).iat,
  });
});

// Global error handler
app.use((err: any, _req: Request, res: Response, _next: NextFunction) => {
  log('error', 'Unhandled error', {
    error: NODE_ENV === 'production' ? 'redacted' : String(err),
  });
  res.status(500).json({ error: 'Internal server error' });
});

// Startup sequence with dependency checks
enforceDependencyPolicy();

app.listen(PORT, () => {
  log('info', `Server started on port ${PORT}`);
});
```

**Defense in Depth Layers**:
1. Dependency hygiene and policy enforcement:
   - `enforceDependencyPolicy()` reads an `npm-audit-summary.json` generated in CI:
   ```bash
   # Example CI step (GitHub Actions / GitLab CI)
   npm ci
   npm audit --production --json > npm-audit-full.json
   node scripts/summarize-audit.js npm-audit-full.json > npm-audit-summary.json
   ```
   - Production refuses to start if critical vulnerabilities are present, making it harder to accidentally run with known-bad packages.

2. Application-layer defenses (rate limiting, security headers, auth hardening):
   - Rate limiting:
   ```typescript
   const apiLimiter = rateLimit({ windowMs: 15 * 60 * 1000, max: 300 });
   app.use('/api', apiLimiter);
   ```
   - Security headers via Helmet reduce exploitation impact for some dependency bugs, especially in middleware or templating libraries.
   - Hardened JWT verification ensures that even if another package is compromised, token abuse is still constrained.

3. Monitoring, logging, and graceful error handling:
   - Centralized JSON logging with `log(level, message, meta)` makes it easy to feed logs into SIEM and detect anomalies (e.g., spikes in JWT verification failures).
   - Global error handler ensures unhandled errors return generic 500 responses without leaking stack traces.
   - Health endpoint `/health` allows uptime checks and can be extended to verify dependency integrity (e.g., checking known-good checksums).

**Additional Protections**:
- Use lockfiles (`package-lock.json` or `pnpm-lock.yaml`) and `npm ci` in CI to ensure reproducible builds and avoid surprise dependency updates.
- Implement a regular dependency upgrade cadence (e.g., weekly/bi-weekly) using tools like Renovate or Dependabot with security-focused review workflows.
- Restrict install sources and verify package integrity: configure the registry (e.g., private npm proxy), enable `npm audit` in your IDE/commit hooks, and consider package signing/verification where supported.
